import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const Signup = () => {
  const [formData, setFormData] = useState({ name: '', email: '', password: '', role: 'member' });
  const navigate = useNavigate();

  const handleSignup = async (e) => {
    e.preventDefault();
    try {
      const { data } = await axios.post('http://localhost:5000/api/auth/register', formData);
      localStorage.setItem('token', data.token);
      localStorage.setItem('role', formData.role);
      navigate('/');
    } catch (err) { alert("Signup failed!"); }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#0f172a] text-white">
      <form onSubmit={handleSignup} className="bg-white/5 p-10 rounded-3xl border border-white/10 w-full max-w-md shadow-2xl">
        <h2 className="text-2xl font-bold mb-6 text-center">Create Account</h2>
        <input className="w-full p-4 bg-white/5 border border-white/10 rounded-xl mb-4" placeholder="Full Name" onChange={e => setFormData({...formData, name: e.target.value})} required/>
        <input className="w-full p-4 bg-white/5 border border-white/10 rounded-xl mb-4" placeholder="Email" onChange={e => setFormData({...formData, email: e.target.value})} required/>
        <input type="password" className="w-full p-4 bg-white/5 border border-white/10 rounded-xl mb-4" placeholder="Password" onChange={e => setFormData({...formData, password: e.target.value})} required/>
        <select className="w-full p-4 bg-[#1e293b] border border-white/10 rounded-xl mb-6 text-white" onChange={e => setFormData({...formData, role: e.target.value})}>
          <option value="member">Team Member</option>
          <option value="admin">Admin / Manager</option>
        </select>
        <button className="w-full py-4 bg-indigo-600 rounded-xl font-bold">Sign Up</button>
        <p className="mt-4 text-center text-gray-400">Already have an account? <a href="/login" className="text-indigo-400">Login</a></p>
      </form>
    </div>
  );
};

export default Signup;
